select LAST_NAME, FIRST_NAME, SALARY as OLD_SALARY, SALARY*1.08 as SALARY_WITH_BONUS
from Employees as E, Jobs as J
where (E.JOB_ID = J.JOB_ID) and (JOB_TITLE='clerk');

select FIRST_NAME, LAST_NAME, SALARY AS OLD_SALARY, SALARY*1.12 AS NEW_SALARY
from Employees, Jobs
where (JOB_TITLE='clerk') and (Jobs.JOB_ID=Employees.JOB_ID);

select first_name, last_name ,salary,salary*1.15 "New_salary"
 from Employees, Jobs
  where Employees.job_id=Jobs.job_id and job_title="clerk";

select FIRST_NAME, LAST_NAME, SALARY, SALARY*1.16 AS NEW_SALARY
from Employees
where JOB_ID = (SELECT JOB_ID from Jobs where JOB_TITLE = 'clerk');

